const headers = $json.headers || {};
const role = String(headers["x-user-role"] || "").trim().toLowerCase();
const id = String(headers["x-user-id"] || role || "").trim();
const name = String(headers["x-user-name"] || role || "").trim();

if (!role) {
  return { json: { statusCode: 401, error: "expired", code: "session_missing" } };
}

return {
  json: {
    session: { id, name, role },
    params: $json.params || {},
    body: $json.body || {},
  },
};

const CONFIG = {
  AIRTABLE_PAT: $env.AIRTABLE_PAT || $env.AIRTABLE_API_KEY || "",
  AIRTABLE_BASE_ID: $env.AIRTABLE_BASE_ID || "",
  AIRTABLE_EPISODE_MEDIA_FIELD: $env.AIRTABLE_EPISODE_MEDIA_FIELD || "media",
};

const request = this.helpers.httpRequest.bind(this.helpers);
const apiKey = String(CONFIG.AIRTABLE_PAT || "").trim();
const baseId = String(CONFIG.AIRTABLE_BASE_ID || "").trim();
const mediaField = String(CONFIG.AIRTABLE_EPISODE_MEDIA_FIELD || "media").trim();
const session = $json.session;
const episodeId = String($json.params?.id || "").trim();
const files = Array.isArray($json.body?.files) ? $json.body.files : [];

if (!apiKey || !baseId) {
  return { json: { statusCode: 500, error: "Airtable config missing in n8n environment", code: "airtable_config_missing" } };
}

if (!session || !["samuel", "mathilde"].includes(session.role)) {
  return { json: { statusCode: 403, error: "forbidden", code: "episode_media_forbidden" } };
}

if (!episodeId || !files.length) {
  return { json: { statusCode: 400, error: "episode id and files are required", code: "episode_media_invalid" } };
}

if (files.length > 8) {
  return { json: { statusCode: 413, error: "Trop de fichiers. Ajoute 8 medias maximum a la fois.", code: "too_many_files" } };
}

const airtable = "https://api.airtable.com/v0/" + baseId;
const uploadBase = "https://content.airtable.com/v0/" + baseId;
const headers = { Authorization: "Bearer " + apiKey };

const fieldQuery =
  "?fields%5B%5D=number&fields%5B%5D=title&fields%5B%5D=date&fields%5B%5D=place&fields%5B%5D=duration&fields%5B%5D=cover_url&fields%5B%5D=notes&fields%5B%5D=music_url&fields%5B%5D=" +
  encodeURIComponent(mediaField);
const escapeFormulaString = (value) => String(value).replace(/'/g, "\\'");

let record;
let recordId = episodeId;
try {
  record = await request({
    method: "GET",
    url: airtable + "/Episodes/" + encodeURIComponent(recordId) + fieldQuery,
    headers,
    json: true,
  });
} catch (directError) {
  try {
    const formula = "OR(RECORD_ID() = '" + escapeFormulaString(episodeId) + "', {id} = '" + escapeFormulaString(episodeId) + "')";
    const data = await request({
      method: "GET",
      url: airtable + "/Episodes?maxRecords=1&filterByFormula=" + encodeURIComponent(formula) + "&" + fieldQuery.slice(1),
      headers,
      json: true,
    });
    record = data.records?.[0];
    recordId = record?.id || "";
  } catch (searchError) {
    return { json: { statusCode: 404, error: "Episode not found: " + (searchError?.message || directError?.message || String(searchError)), code: "episode_missing" } };
  }
}

if (!record || !recordId) {
  return { json: { statusCode: 404, error: "Episode not found", code: "episode_missing" } };
}

let finalFields = record.fields || {};

for (const input of files) {
  const file = String(input?.file || "").replace(/^data:.*?;base64,/, "");
  const filename = String(input?.filename || "media-" + Date.now()).trim();
  const contentType = String(input?.contentType || "application/octet-stream").trim();
  const isMedia = contentType.startsWith("image/") || contentType.startsWith("video/");
  const fileBytes = Math.floor((file.length * 3) / 4);

  if (!file || !isMedia) {
    return { json: { statusCode: 400, error: "Only image and video files are accepted", code: "media_type_invalid" } };
  }

  if (fileBytes > 5 * 1024 * 1024) {
    return { json: { statusCode: 413, error: "Chaque media doit faire moins de 5 Mo.", code: "media_too_large" } };
  }

  try {
    const uploaded = await request({
      method: "POST",
      url: uploadBase + "/" + encodeURIComponent(recordId) + "/" + encodeURIComponent(mediaField) + "/uploadAttachment",
      headers: { ...headers, Accept: "application/json" },
      body: { file, filename, contentType },
      json: true,
    });
    finalFields = uploaded.fields || finalFields;
  } catch (error) {
    return { json: { statusCode: 500, error: "Airtable media upload failed: " + (error?.message || String(error)), code: "airtable_media_upload_failed" } };
  }
}

const mediaFromAttachments = (attachments) =>
  (Array.isArray(attachments) ? attachments : []).map((attachment) => {
    const contentType = String(attachment.type || "");
    return {
      id: attachment.id || "",
      url: attachment.url || "",
      filename: attachment.filename || "media",
      type: contentType.startsWith("video/") ? "video" : contentType.startsWith("image/") ? "image" : "file",
      contentType,
      size: attachment.size || 0,
    };
  });

const media = mediaFromAttachments(finalFields[mediaField]);

return {
  json: {
    episode: {
      id: String(finalFields.id || recordId),
      number: Number(finalFields.number || 0),
      title: String(finalFields.title || ""),
      date: String(finalFields.date || ""),
      place: String(finalFields.place || ""),
      duration: String(finalFields.duration || ""),
      cover_url: String(finalFields.cover_url || media.find((item) => item.type === "image")?.url || ""),
      media,
      notes: String(finalFields.notes || ""),
      music_url: String(finalFields.music_url || ""),
    },
  },
};
